using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n;
char c;
int aa;
long long ans, lastans;
int a[20000005];
int main(void)
{
	cin >> n;
	aa = 1e7;
	lastans = 0;
	a[aa] = 1;
	for (int i = 1; i <= n; i++)
	{
		cin >> c;
		if (c == '1')
		{
			lastans += a[aa];
			aa++;
		}
		else
		{
			lastans -= a[aa - 1];
			aa--;
		}
		ans += lastans;
		a[aa]++;
	}
	cout << ans;
	return false;
}
